1	type Quote = { premium: number };
2	type Item = { type: string };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	};
12	const THREE_RUNE_BLOCK_PREMIUM = 60;
13	
14	const basePremiumFor = (item: Item): number =>
15	  BASE_PREMIUM_BY_TYPE[item.type];
16	
17	const sumBasePremiums = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
19	
20	const isThreeRuneBlock = (items: Item[]): boolean =>
21	  items.length === 3 && items.every((item) => item.type === "rune");
22	
23	const componentsPremium = (items: Item[]): number =>
24	  isThreeRuneBlock(items) ? THREE_RUNE_BLOCK_PREMIUM : sumBasePremiums(items);
25	
26	export const quote = (input: { items: Item[] }): Quote => ({
27	  premium: componentsPremium(input.items) + PROCESSING_FEE,
28	});
29	
30	export const claim = (_input: unknown): unknown => undefined;
31
